CREATE OR REPLACE FUNCTION f_get_loan_code ( as_loan_contract text ) RETURNS varchar AS $body$
DECLARE


 ls_loan_code  sc_lon_m_loan_card.loan_code%type;


BEGIN

    select loan_code into STRICT ls_loan_code
    from sc_lon_m_loan_card
    where trim(both loan_contract_no) = trim(both as_loan_contract) 
;


